function shallowCopy(src) {
  var dst = {};
  for (var prop in src) {
    if (src.hasOwnProperty(prop)) {
      dst[prop] = src[prop];
    }
  }
  return dst;
}
console.log('obj1', obj1); //{name:'zhangsan','age' :  '18','language' : [1,["\u4E8C","\u4E09"],[4,5]],}
